class Solution:
    def constructTransformedArray(self, nums):
        # independent re-derivation: physically step one hop at a time instead
        # of jumping straight to the modular offset
        n = len(nums)
        result = []
        for i in range(n):
            if nums[i] == 0:
                result.append(0)
                continue
            pos = i
            step = 1 if nums[i] > 0 else -1
            for _ in range(abs(nums[i])):
                pos = (pos + step) % n
            result.append(nums[pos])
        return result

