class Solution:
    def constructTransformedArray(self, nums):
        n = len(nums)
        result = []
        for i in range(n):
            if nums[i] == 0:
                result.append(0)
            else:
                dest = (i + nums[i]) % n
                result.append(nums[dest])
        return result

