var constructTransformedArray = function(nums) {
    const n = nums.length;
    const result = new Array(n);
    for (let i = 0; i < n; i++) {
        if (nums[i] === 0) {
            result[i] = 0;
        } else {
            const dest = ((i + nums[i]) % n + n) % n;
            result[i] = nums[dest];
        }
    }
    return result;
};
